100	  .led-grid .led { width: 100%; aspect-ratio: 1 / 1; max-height: 22px; min-height: 12px;
101	    display: grid; place-items: center; font-size: 8px; font-weight: 700; }
102	  .led.up { background: rgba(0,255,102,0.18); color: var(--green); border: 1px solid rgba(0,255,102,0.55); box-shadow: inset 0 0 6px rgba(0,255,102,0.35); }
103	  .led.dn { background: rgba(255,51,68,0.16); color: var(--red); border: 1px solid rgba(255,51,68,0.5); box-shadow: inset 0 0 6px rgba(255,51,68,0.3); }
104	  .led.flat { background: rgba(112,112,112,0.12); color: var(--muted); border: 1px solid var(--line-strong); }
105	  .led-grid .net { font-size: 10px; color: var(--fg-strong); font-weight: 700; text-align: right; letter-spacing: 0.04em; }
106	  .led-grid .net.up { color: var(--green); }
107	  .led-grid .net.dn { color: var(--red); }
108	  .led-legend { display: flex; gap: 12px; margin-top: 8px; font-size: 9px; color: var(--muted); letter-spacing: 0.08em; }
109	  .led-legend .lg { display: flex; align-items: center; gap: 4px; }
110	  .led-legend i { width: 10px; height: 10px; }
111	  .led-legend i.up { background: rgba(0,255,102,0.45); border: 1px solid var(--green); }
112	  .led-legend i.dn { background: rgba(255,51,68,0.4); border: 1px solid var(--red); }
113	  .led-legend i.flat { background: rgba(112,112,112,0.2); border: 1px solid var(--muted); }
114	
115	  /* MOD 2: Activity log */
116	  .log-list { font-size: 10px; line-height: 1.5; letter-spacing: 0.02em; }
117	  .log-row { display: grid; grid-template-columns: 56px 38px 1fr auto; gap: 8px; padding: 4px 0; border-bottom: 1px dotted var(--line); }
118	  .log-row:last-child { border-bottom: 0; }
119	  .log-time { color: var(--dim); }
120	  .log-type { color: var(--amber); font-weight: 700; letter-spacing: 0.06em; }
121	  .log-type.cl { color: var(--green); }
122	  .log-type.cr { color: var(--cyan); }
123	  .log-msg { color: var(--fg); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
124	  .log-d { font-weight: 700; }
125	  .log-d.up { color: var(--green); }
126	  .log-d.dn { color: var(--red); }
127	
128	  /* MOD 3: ASCII heatmap */
129	  .heat-wrap { font-family: var(--font-mono); font-size: 10px; line-height: 1.55; color: var(--fg); }
130	  .heat-wrap .heat-head, .heat-wrap .heat-row { display: grid; grid-template-columns: 36px repeat(4, 1fr); gap: 6px; }
131	  .heat-wrap .heat-head { color: var(--muted); font-size: 9px; letter-spacing: 0.1em; padding-bottom: 4px; border-bottom: 1px dotted var(--line-strong); margin-bottom: 4px; }
132	  .heat-wrap .heat-row { padding: 3px 0; }
133	  .heat-wrap .heat-row .m { color: var(--muted); font-weight: 600; letter-spacing: 0.06em; }
134	  .heat-cell { padding: 2px 4px; text-align: center; font-weight: 700; letter-spacing: 0.04em; }
135	  .heat-cell.h0 { background: #0f0f0f; color: var(--dim); }
136	  .heat-cell.h1 { background: rgba(255,176,0,0.12); color: var(--amber-dim); }
137	  .heat-cell.h2 { background: rgba(255,176,0,0.28); color: var(--amber); }
138	  .heat-cell.h3 { background: rgba(255,176,0,0.5); color: #fff; }
139	  .heat-cell.h4 { background: rgba(255,176,0,0.78); color: #050505; }

55:  .kpi-strip { background: var(--bg-2); border-bottom: 1px solid var(--line); display: grid; grid-template-columns: repeat(4, 1fr); }
56:  .kpi-cell { padding: 14px 22px; border-right: 1px solid var(--line); position: relative; }
57:  .kpi-cell:last-child { border-right: 0; }
58:  .kpi-cell::before { content:''; position: absolute; left: 0; top: 12px; bottom: 12px; width: 3px; }
59:  .kpi-cell.cust-create::before { background: var(--cyan); }
60:  .kpi-cell.cust-close::before { background: var(--green); }
61:  .kpi-cell.int-create::before { background: var(--amber); }
62:  .kpi-cell.int-close::before { background: var(--magenta); }

40:  /* topbar */
41:  .topbar { background: var(--bg-2); border-bottom: 1px solid var(--line); display: grid;
44:  .topbar .lbl { color: var(--muted); }
45:  .topbar .v { color: var(--amber); }
46:  .topbar .v.up { color: var(--green); }
47:  .topbar .v.dn { color: var(--red); }
48:  .topbar .sep { color: var(--dim); }
